#include<iostream>#include<vector>using namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int>p(n + 1);        vector<int>free(n+1,0);        for(int i=1;i<=n;i++){            cin>>p[i];            free[i]= free[i - 1]+( p[i]<=i? 1:0);        }        int max_s= free[n];        for(int i=1;i<=n;i++){                        if(p[i] > i){                int c= free[p[i] - 1] + 1;                max_s= max(max_s,c);            }                    }         cout<<max_s<<"\n";    }}